.task-pool-manager {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 16px;
  background: #ffffff;
  color: #111827;
}

.header-actions {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
  gap: 16px;
  flex-wrap: wrap;

  .search-bar {
    display: flex;
    align-items: center;
    background: #f3f4f6;
    border: 1px solid #e5e7eb;
    border-radius: 6px;
    padding: 6px 12px;
    flex: 1;
    max-width: 400px;
    transition: border-color 0.2s;

    &:focus-within {
      border-color: #6366f1;
      background: #ffffff;
      box-shadow: 0 0 0 2px rgba(99, 102, 241, 0.1);
    }

    .search-icon {
      margin-right: 8px;
      color: #9ca3af;
      font-size: 14px;
    }

    input {
      border: none;
      background: transparent;
      outline: none;
      width: 100%;
      font-size: 14px;
      color: #111827;
    }
  }
}

.stats-bar {
  font-size: 13px;
  color: #6b7280;
  margin-bottom: 16px;
  padding-bottom: 12px;
  border-bottom: 1px solid #e5e7eb;
  display: flex;
  align-items: center;

  strong {
    color: #111827;
    font-weight: 600;
  }

  .separator {
    margin: 0 12px;
    color: #d1d5db;
  }
}

.empty-state {
  text-align: center;
  padding: 40px;
  color: #6b7280;
  background: #f9fafb;
  border-radius: 8px;
  border: 1px dashed #d1d5db;
  margin-top: 20px;
}

.task-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); /* 减小最小宽度 */
  gap: 12px; /* 减小网格间距 */
  overflow-y: auto;
  padding-bottom: 20px;
  align-content: start;
}

.task-card {
  background: #ffffff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 12px; /* 减小内边距 */
  display: flex;
  flex-direction: column;
  transition: all 0.2s ease;
  box-shadow: 0 1px 2px rgba(0,0,0,0.05);

  &:hover {
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
    border-color: #d1d5db;
  }

  &.is-orphaned {
    border-style: dashed;
    background: #fafafa;
  }
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center; /* 垂直居中对齐 */
  margin-bottom: 8px; /* 减小下边距 */
  gap: 8px;

  .title-area {
    display: flex;
    flex-direction: row; /* 水平排列 */
    align-items: center;
    gap: 8px;
    overflow: hidden;
  }

  .task-name {
    font-size: 15px; /* 稍微减小字号 */
    font-weight: 600;
    color: #111827;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .status-badge {
    flex-shrink: 0; /* 防止被挤压 */
    font-size: 11px;
    padding: 2px 6px;
    border-radius: 10px;
    background: #e5e7eb;
    color: #4b5563;
    line-height: 1.2;

    &.active {
      background: #dcfce7;
      color: #166534;
    }

    &.event-trigger {
      background: #e0e7ff;
      color: #3730a3;
    }
  }
}

.card-actions {
  display: flex;
  gap: 2px; /* 减小按钮间距 */
  flex-shrink: 0;
}

.card-body {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

.comment-text {
  font-size: 12px; /* 减小字号 */
  color: #6b7280;
  margin-bottom: 8px; /* 减小下边距 */
  display: -webkit-box;
  -webkit-line-clamp: 1; /* 改为单行显示，节省空间 */
  -webkit-box-orient: vertical;
  overflow: hidden;
  line-height: 1.4;
}

.usage-section {
  background: #f9fafb;
  border-radius: 6px;
  padding: 6px 8px; /* 减小内边距 */
  border: 1px solid #f3f4f6;
  display: flex; /* 改为 Flex 布局 */
  align-items: center; /* 垂直居中 */
  gap: 8px;

  .usage-title {
    font-size: 12px;
    color: #4b5563;
    font-weight: 500;
    white-space: nowrap; /* 防止换行 */
    flex-shrink: 0;
  }

  .usage-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 4px; /* 减小标签间距 */
  }

  .usage-tag {
    font-size: 11px;
    background: #e0e7ff;
    color: #3730a3;
    padding: 2px 6px;
    border-radius: 4px;
    white-space: nowrap;
    max-width: 80px; /* 稍微减小最大宽度 */
    overflow: hidden;
    text-overflow: ellipsis;

    &.more {
      background: #f3f4f6;
      color: #4b5563;
      cursor: help;
    }

    &.orphaned {
      background: #fee2e2;
      color: #991b1b;
      max-width: none;
    }
  }
}

/* Buttons */
.btn {
  padding: 8px 16px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-size: 14px;
  font-weight: 500;
  transition: background 0.2s;

  &.primary {
    background: #4f46e5;
    color: white;
    &:hover { background: #4338ca; }
  }

  &.icon-btn {
    padding: 4px;
    background: transparent;
    border-radius: 4px;
    font-size: 13px; /* 稍微减小图标大小 */
    line-height: 1;
    &:hover { background: #f3f4f6; }
    &.danger-text:hover { background: #fee2e2; }
  }
}

/* Custom Scrollbar */
.custom-scrollbar {
  &::-webkit-scrollbar { width: 6px; }
  &::-webkit-scrollbar-track { background: transparent; }
  &::-webkit-scrollbar-thumb { background: #d1d5db; border-radius: 3px; }
  &::-webkit-scrollbar-thumb:hover { background: #9ca3af; }
}

/* Dark Mode */
.dark-mode {
  background: #111827;
  color: #e2e8f0;

  .header-actions .search-bar {
    background: #1f2937;
    border-color: #374151;
    input { color: #e2e8f0; }
    &:focus-within {
      border-color: #818cf8;
      background: #111827;
    }
  }

  .stats-bar {
    border-bottom-color: #374151;
    color: #9ca3af;
    strong { color: #e2e8f0; }
    .separator { color: #4b5563; }
  }

  .empty-state {
    background: #1f2937;
    border-color: #374151;
    color: #9ca3af;
  }

  .task-card {
    background: #1f2937;
    border-color: #374151;
    &:hover { border-color: #4b5563; background: #2d3748; }
    &.is-orphaned { background: #1a202c; border-color: #4b5563; }
  }

  .task-name { color: #e2e8f0; }
  .status-badge { background: #374151; color: #9ca3af; }
  .status-badge.active { background: #064e3b; color: #6ee7b7; }
  .status-badge.event-trigger { background: #312e81; color: #c7d2fe; }

  .comment-text { color: #9ca3af; }

  .usage-section {
    background: #111827;
    border-color: #374151;
    .usage-title { color: #9ca3af; }
    .usage-tag {
      background: #312e81;
      color: #c7d2fe;
      &.more { background: #374151; color: #d1d5db; }
      &.orphaned { background: #7f1d1d; color: #fecaca; }
    }
  }

  .btn.icon-btn {
    &:hover { background: #374151; }
    &.danger-text:hover { background: #7f1d1d; }
  }
}
