/* 样式保持不变，或者你可以根据需要微调 */
.main-container {
  padding: 10px;
  height: 100%;
  display: flex;
  flex-direction: column;
  position: relative;
}

.title {
  margin: 8px 0 16px;
  font-size: 18px;
  font-weight: 600;
  color: #111827;
}

.page-tabs {
  display: flex;
  margin-bottom: 20px;
  border-bottom: 1px solid #e5e7eb;
  /* 如果标签太多，允许换行或滚动 */
  flex-wrap: wrap;
}

.tab-button {
  padding: 10px 20px;
  border: none;
  background: transparent;
  cursor: pointer;
  font-size: 14px;
  color: #6b7280;
  border-bottom: 2px solid transparent;
  text-decoration: none;
  transition: all 0.2s;

  &:hover {
    color: #111827;
    background-color: rgba(0,0,0,0.02);
  }

  &.active {
    color: #6366f1;
    border-bottom: 2px solid #6366f1;
    font-weight: 500;
  }
}

.content-area {
  flex: 1;
  overflow-y: auto;
  padding-bottom: 20px;
}

.footer {
  display: flex;
  justify-content: flex-end;
  padding-top: 10px;
  border-top: 1px solid #e5e7eb;
}

.btn {
  padding: 6px 16px;
  border: none;
  border-radius: 8px;
  font-size: 14px;
  cursor: pointer;
  background: #f3f4f6;
  color: #111827;
  transition: background 0.2s;

  &:hover {
    background: #e5e7eb;
  }
}

/* Dark Mode Support */
.dark-mode {
  .title { color: #e2e8f0; }

  .page-tabs { border-bottom-color: #4b5563; }

  .tab-button {
    color: #9ca3af;
    &:hover { color: #e2e8f0; background-color: rgba(255,255,255,0.05); }
    &.active { color: #818cf8; border-bottom-color: #818cf8; }
  }

  .footer { border-top-color: #4b5563; }

  .btn {
    background: #4b5563;
    color: #e2e8f0;
    &:hover { background: #6b7280; }
  }
}
