.api-config-container {
  display: flex;
  height: 100%; /* 填满父容器 */
  min-height: 500px;
  gap: 16px;
  overflow: hidden;
  position: relative; /* 确保移动端绝对定位相对于此容器 */
}

/* 左侧边栏 */
.sidebar {
  width: 220px;
  flex-shrink: 0;
  border-right: 1px solid #e5e7eb;
  display: flex;
  flex-direction: column;
  padding-right: 10px;
}

.sidebar-header {
  margin-bottom: 10px;
}

/* 新增：导入导出容器样式 */
.import-export-wrapper {
  margin-top: 8px;

  /* 穿透样式以适配组件内部布局 */
  :deep(.file-import-export) {
    width: 100%;
  }

  :deep(.button-group) {
    display: flex;
    gap: 6px;
  }

  :deep(.btn) {
    flex: 1;
    justify-content: center;
  }
}

.config-list {
  flex: 1;
  overflow-y: auto;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.config-item {
  padding: 10px;
  border-radius: 6px;
  cursor: pointer;
  border: 1px solid transparent;
  background: #f9fafb;
  transition: all 0.2s;

  &:hover {
    background: #f3f4f6;
  }

  &.active {
    background: #e0e7ff;
    border-color: #6366f1;
    .config-name { color: #4338ca; font-weight: 600; }
  }
}

.config-name {
  font-size: 14px;
  color: #1f2937;
  margin-bottom: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.config-source {
  font-size: 11px;
  color: #6b7280;
}

.empty-tip {
  text-align: center;
  color: #9ca3af;
  font-size: 13px;
  margin-top: 20px;
}

/* 右侧主内容 */
.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: #fff; /* 确保背景色，防止移动端透明 */
  transition: transform 0.3s ease-in-out;
}

.no-selection {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #9ca3af;
  border: 2px dashed #e5e7eb;
  border-radius: 8px;
}

.editor-panel {
  display: flex;
  flex-direction: column;
  height: 100%;
}

.panel-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-bottom: 12px;
  border-bottom: 1px solid #e5e7eb;
  margin-bottom: 16px;

  .title-row {
    display: flex;
    align-items: center;
    gap: 8px;
    overflow: hidden;
  }

  h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 600;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }
}

.header-actions {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}

.mobile-back-btn {
  display: none; /* 默认隐藏 */
}

.form-scroll-area {
  flex: 1;
  overflow-y: auto;
  padding-right: 8px;
}

/* 表单样式 */
.form-group {
  margin-bottom: 16px;

  label {
    display: flex;
    align-items: center;
    gap: 6px;
    margin-bottom: 6px;
    font-size: 13px;
    font-weight: 500;
    color: #000000 !important;
  }

  input, select {
    width: 100%;
    padding: 8px 10px;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    font-size: 14px;
    /* 强制覆盖浏览器默认背景和颜色 */
    background: #fff !important;
    color: #000000 !important;

    &:focus {
      outline: none;
      border-color: #6366f1;
      box-shadow: 0 0 0 2px rgba(99, 102, 241, 0.1);
    }
  }
}

.row-group {
  display: flex;
  gap: 12px;
  .half { flex: 1; }
}

.input-with-btn {
  display: flex;
  gap: 8px;

  select, input {
    flex: 1;
  }
}

.divider {
  border: none;
  border-top: 1px solid #e5e7eb;
  margin: 20px 0;
}

.tip-card {
  background: #fffbeb;
  border: 1px solid #fcd34d;
  color: #b45309;
  padding: 8px 12px;
  border-radius: 6px;
  font-size: 12px;
  margin-bottom: 16px;
}

.test-area {
  margin-top: 10px;
  padding-top: 10px;
}

/* 按钮通用 */
.btn {
  padding: 6px 12px;
  border-radius: 6px;
  border: 1px solid #d1d5db;
  background: #fff;
  cursor: pointer;
  font-size: 13px;
  transition: all 0.2s;

  &:hover { background: #f3f4f6; }

  &.primary {
    background: #6366f1;
    color: white;
    border-color: #6366f1;
    &:hover { background: #4f46e5; }
  }

  &.danger {
    background: #fee2e2;
    color: #991b1b;
    border-color: #fecaca;
    &:hover { background: #fecaca; }
  }

  &.full-width { width: 100%; }

  &.small { padding: 4px 8px; font-size: 12px; }

  &.icon-btn {
    padding: 0 10px;
    font-size: 16px;
    line-height: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    height: 32px; /* 固定高度确保对齐 */
  }
}

/* Dark Mode */
.dark-mode {
  .sidebar { border-right-color: #4b5563; }

  .config-item {
    background: #374151;
    color: #e2e8f0;
    &:hover { background: #4b5563; }
    &.active {
      background: #312e81;
      border-color: #818cf8;
      .config-name { color: #e0e7ff; }
    }
  }

  .config-name { color: #e2e8f0; }
  .config-source { color: #9ca3af; }

  .main-content {
    background: #1f2937; /* 深色模式背景 */
  }

  .no-selection { border-color: #4b5563; color: #6b7280; }

  .panel-header { border-bottom-color: #4b5563; h4 { color: #e2e8f0; } }

  .form-group {
    label { color: #cbd5e1 !important; }
    input, select {
      /* 强制覆盖深色模式下的背景和颜色 */
      background: #374151 !important;
      border-color: #4b5563;
      color: #e2e8f0 !important;
      &:focus { border-color: #818cf8; }
    }
  }

  .divider { border-top-color: #4b5563; }

  .tip-card {
    background: #451a03;
    border-color: #92400e;
    color: #fcd34d;
  }

  .btn {
    background: #374151;
    border-color: #4b5563;
    color: #e2e8f0;
    &:hover { background: #4b5563; }

    &.primary {
      background: #4f46e5;
      border-color: #4f46e5;
      color: #fff;
    }

    &.danger {
      background: #7f1d1d;
      border-color: #991b1b;
      color: #fecaca;
    }
  }
}

/* ------------------------------------------------------------------ */
/* 移动端适配 (小于 768px) */
/* ------------------------------------------------------------------ */
@media (max-width: 768px) {
  .api-config-container {
    flex-direction: row; /* 保持 row，通过绝对定位处理 */
    overflow: hidden;
  }

  .sidebar {
    width: 100%; /* 占满宽度 */
    border-right: none;
    padding-right: 0;
  }

  .main-content {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: 10;
    transform: translateX(100%); /* 默认移出屏幕右侧 */
    padding: 10px; /* 增加内边距 */
  }

  /* 当有选中配置时，滑入屏幕 */
  .main-content.mobile-visible {
    transform: translateX(0);
  }

  /* 隐藏未选中时的占位符，因为移动端默认显示列表 */
  .no-selection {
    display: none;
  }

  /* 显示返回按钮 */
  .mobile-back-btn {
    display: flex;
    margin-right: 8px;
  }

  /* 调整头部布局 */
  .panel-header {
    flex-direction: row;
    align-items: center;

    h4 {
      font-size: 14px;
    }
  }

  .header-actions {
    .btn {
      padding: 4px 8px;
      font-size: 12px;
    }
  }
}
