.file-import-export {
  display: inline-block;
}

.button-group {
  display: flex;
  gap: 8px;
  align-items: center;
}

.btn {
  padding: 5px 12px;
  border: none;
  border-radius: 6px;
  font-size: 12px;
  cursor: pointer;
  transition: all 0.2s;
  background: #f3f4f6;
  color: #111827;
  box-shadow: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  font-weight: 500;
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.btn:hover:not(.disabled) {
  background: #e5e7eb;
  color: #000000;
}

.btn.primary {
  background: #4f46e5;
  color: #ffffff;
  font-weight: 500;
}

.btn.primary:hover:not(.disabled) {
  background: #4338ca;
  color: #ffffff;
}

.btn.disabled {
  opacity: 0.6;
  cursor: not-allowed;
}

.loading-spinner {
  display: inline-block;
  width: 12px;
  height: 12px;
  border: 2px solid #f3f4f6;
  border-top: 2px solid #6366f1;
  border-radius: 50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

.status-message {
  padding: 6px 10px;
  border-radius: 4px;
  font-size: 11px;
  margin-top: 8px;
}

.status-message.success {
  background: #d1fae5;
  color: #065f46;
  border: 1px solid #a7f3d0;
}

.status-message.error {
  background: #fee2e2;
  color: #991b1b;
  border: 1px solid #fecaca;
}

.status-message.warning {
  background: #fef3c7;
  color: #92400e;
  border: 1px solid #fde68a;
}

/* 黑夜模式 */
.dark-mode {
  .btn {
    background: #4b5563;
    color: #e2e8f0;
    box-shadow: 0 1px 2px 0 rgba(0, 0, 0, 0.2);

    &:hover:not(.disabled) {
      background: #6b7280;
      color: #f8fafc;
    }

    &.primary {
      background: #4f46e5;
      color: #f8fafc;

      &:hover:not(.disabled) {
        background: #6366f1;
        color: #f8fafc;
      }
    }

    &.disabled {
      opacity: 0.6;
      color: #9ca3af;
    }
  }

  .loading-spinner {
    border: 2px solid #4b5563;
    border-top: 2px solid #818cf8;
  }

  .status-message {
    &.success {
      background: #065f46;
      color: #a7f3d0;
      border: 1px solid #065f46;
    }

    &.error {
      background: #991b1b;
      color: #fecaca;
      border: 1px solid #991b1b;
    }

    &.warning {
      background: #92400e;
      color: #fef08a;
      border: 1px solid #92400e;
    }
  }
