.json-tree {
  font-family: monospace;
  font-size: 12px;
  overflow-x: auto;
  padding: 10px;
  background-color: #fff; /* 保持与 Edit 风格一致的背景 */
  white-space: nowrap;
}

.empty-tree {
  padding: 20px;
  color: #9ca3af;
  text-align: center;
  font-style: italic;
}

/* 黑夜模式 */
.dark-mode .json-tree {
  background-color: #1f2937;
  color: #e2e8f0;
}

.dark-mode .empty-tree {
  color: #6b7280;
}
