.json-node {
  position: relative;
}

.line {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px;
  border-radius: 4px;
  transition: background-color 0.2s;

  &:hover {
    background-color: #f1f5f9;
    .actions {
      opacity: 1;
    }
  }
}

.arrow {
  cursor: pointer;
  width: 16px;
  text-align: center;
  font-size: 10px;
  color: #94a3b8;
  transition: transform 0.2s;
  &.expanded {
    transform: rotate(90deg);
  }
}

.space {
  width: 16px;
}

.key {
  color: #1e293b;
  font-weight: 600;
}

.value {
  cursor: pointer;
  &.type-string {
    color: #059669;
  }
  &.type-number {
    color: #dc2626;
  }
  &.type-boolean {
    color: #7c3aed;
  }
  &.type-null {
    color: #64748b;
    font-style: italic;
  }
}

.preview {
  color: #94a3b8;
  font-style: italic;
}

.editor-container {
  display: flex;
  gap: 6px;
  align-items: center;
}

.edit-select,
.edit-input {
  padding: 2px 6px;
  font-size: 12px;
  border: 1px solid #cbd5e1;
  border-radius: 4px;
  background-color: #fff !important;
  color: #1e293b !important;
  font-family: monospace;
}

/* 强制下拉框选项的颜色 */
.edit-select option {
  background: #fff !important;
  color: #1e293b !important;
}

// 操作按钮区域 (Flexbox 布局)
.actions {
  margin-left: auto; // 关键：将按钮推到最右边
  display: flex;
  gap: 4px;
  opacity: 0; // 默认隐藏
  transition: opacity 0.2s;
}

.btn-action {
  border: none;
  background: transparent;
  cursor: pointer;
  color: #64748b;
  font-size: 14px;
  width: 24px;
  height: 24px;
  border-radius: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  &:hover {
    background-color: #e2e8f0;
    color: #1e293b;
  }
  &.danger:hover {
    background-color: #fee2e2;
    color: #ef4444;
  }
  &.save {
    color: #10b981;
  }
  &.cancel {
    color: #ef4444;
  }
}

.children-container {
  padding-left: 10px;
  border-left: 1px dashed #e2e8f0;
}

/* 黑夜模式 */
.dark-mode {
  .line {
    &:hover {
      background-color: #374151;
    }
  }

  .arrow {
    color: #94a3b8;

    &.expanded {
      color: #cbd5e1;
    }
  }

  .key {
    color: #e2e8f0;
  }

  .value {
    &.type-string {
      color: #34d399;
    }
    &.type-number {
      color: #f87171;
    }
    &.type-boolean {
      color: #a78bfa;
    }
    &.type-null {
      color: #9ca3af;
    }
  }

  .preview {
    color: #9ca3af;
  }

  .edit-select,
  .edit-input {
    background-color: #374151 !important;
    color: #e2e8f0 !important;
    border-color: #4b5563;
  }

  .edit-select option {
    background: #374151 !important;
    color: #e2e8f0 !important;
  }

  .btn-action {
    color: #9ca3af;

    &:hover {
      background-color: #4b5563;
      color: #f8fafc;
    }

    &.danger:hover {
      background-color: #450a0a;
      color: #fecaca;
    }

    &.save {
      color: #34d399;
    }

    &.cancel {
      color: #f87171;
    }
  }
}
