.rule-selector {
  padding: 0 4px;
}

.header-actions {
  margin-bottom: 20px;
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  justify-content: space-between;
  align-items: center;

  .input-group {
    display: flex;
    gap: 10px;
    width: 100%;
    max-width: 400px;

    input {
      flex: 1;
      padding: 8px 12px;
      border: 1px solid #e5e7eb;
      border-radius: 6px;
      outline: none;
      transition: border-color 0.2s;
      color: #111827;
      min-width: 0; /* 防止 flex 子项溢出 */

      &:focus {
        border-color: #6366f1;
        box-shadow: 0 0 0 2px rgba(99, 102, 241, 0.1);
      }
    }

    button {
      white-space: nowrap;
    }
  }
}

.empty-state {
  text-align: center;
  padding: 40px;
  color: #6b7280;
  background: #f9fafb;
  border-radius: 8px;
  border: 1px dashed #d1d5db;
}

.rule-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.rule-card {
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 16px;
  transition: all 0.2s;

  &:hover {
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
  }

  &.active-card {
    border-color: #6366f1;
    background: #f5f7ff;
    box-shadow: 0 0 0 1px #6366f1;
  }
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 8px;
  gap: 10px;
}

.rule-info {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;

  .rule-name {
    font-size: 16px;
    font-weight: 600;
    color: #1f2937;
    word-break: break-all;
  }

  .rule-tags {
    display: flex;
    gap: 6px;
  }
}

.rule-comment {
  font-size: 13px;
  color: #6b7280;
  margin-bottom: 12px;
  padding-bottom: 8px;
  border-bottom: 1px dashed #e5e7eb;
  white-space: pre-wrap;
  display: flex;
  align-items: flex-start;
  gap: 6px;
}

.card-actions {
  display: flex;
  gap: 8px;
  flex-shrink: 0;
}

.card-preview {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.task-pill {
  font-size: 12px;
  background: #e5e7eb;
  color: #4b5563;
  padding: 2px 8px;
  border-radius: 12px;

  &.missing-task {
    background: #fee2e2;
    color: #991b1b;
    border: 1px solid #fecaca;
  }
}

.no-task-tip {
  font-size: 12px;
  color: #9ca3af;
  font-style: italic;
}

/* Tags */
.tag {
  font-size: 12px;
  padding: 2px 8px;
  border-radius: 4px;
  white-space: nowrap;

  &.success {
    background: #d1fae5;
    color: #065f46;
  }

  &.info {
    background: #e0f2fe;
    color: #1e40af;
  }
}

/* Buttons */
.btn {
  padding: 8px 16px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-size: 14px;
  transition: background 0.2s;
  display: inline-flex;
  align-items: center;
  justify-content: center;

  &.small {
    padding: 4px 10px;
    font-size: 12px;
  }

  &.primary {
    background: #6366f1;
    color: white;
    &:hover {
      background: #4f46e5;
    }
  }

  &.info {
    background: #0ea5e9; /* Sky blue / Cyan */
    color: white;
    &:hover {
      background: #0284c7;
    }
  }

  &.secondary {
    background: #fff;
    border: 1px solid #d1d5db;
    color: #374151;
    &:hover {
      background: #f3f4f6;
    }
  }

  &.danger {
    background: #fee2e2;
    color: #991b1b;
    &:hover {
      background: #fecaca;
    }
  }

  /* Disabled state */
  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    &:hover {
      background: inherit;
      border-color: inherit;
      color: inherit;
    }
  }
}

/* Mobile Adaptation */
@media (max-width: 640px) {
  .header-actions {
    flex-direction: column;
    align-items: stretch;

    .input-group {
      max-width: 100%;
    }
  }

  .card-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 12px;
  }

  .rule-info {
    width: 100%;
    justify-content: space-between;
  }

  .card-actions {
    width: 100%;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 8px;

    .btn {
      flex: 1 0 auto; /* 按钮自动填充宽度 */
      min-width: 48px; /* 保证最小点击区域 */
      padding: 8px 12px; /* 增加移动端点击区域 */
    }

    /* 上下移按钮可以稍微窄一点 */
    .btn-move {
      flex: 0 0 auto;
      min-width: 36px;
    }
  }
}

/* Dark Mode Adaption */
.dark-mode {
  .header-actions input {
    background: #374151;
    border-color: #4b5563;
    color: #e2e8f0;
    &:focus {
      border-color: #818cf8;
    }
  }

  .empty-state {
    background: #374151;
    border-color: #4b5563;
    color: #9ca3af;
  }

  .rule-card {
    background: #1f2937;
    border-color: #4b5563;

    &.active-card {
      background: #312e81; /* Dark indigo */
      border-color: #818cf8;
      box-shadow: 0 0 0 1px #818cf8;
    }

    .rule-name {
      color: #e2e8f0;
    }
  }

  .rule-comment {
    color: #9ca3af;
    border-bottom-color: #4b5563;
  }

  .task-pill {
    background: #374151;
    color: #cbd5e1;

    &.missing-task {
      background: #450a0a;
      color: #fca5a5;
      border-color: #7f1d1d;
    }
  }

  .tag.success {
    background: #064e3b;
    color: #a7f3d0;
  }

  .tag.info {
    background: #1e3a8a;
    color: #bfdbfe;
  }

  /* Dark mode for new buttons */
  .btn.info {
    background: #0369a1;
    color: #e0f2fe;
    &:hover {
      background: #075985;
    }
  }

  .btn.secondary {
    background: #374151;
    border-color: #4b5563;
    color: #e2e8f0;
    &:hover {
      background: #4b5563;
    }
  }

  .btn.danger {
    background: #7f1d1d;
    color: #fecaca;
    &:hover {
      background: #991b1b;
    }
  }
}
