.json-node {
  position: relative;
  font-family: monospace;
  font-size: 12px;
}

.line {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 2px 4px; /*稍微调整padding使其更紧凑*/
  border-radius: 4px;
  transition: background-color 0.2s;
  min-height: 24px;

  &:hover {
    background-color: #f1f5f9;
    .actions {
      opacity: 1;
    }
  }
}

.arrow {
  cursor: pointer;
  width: 16px;
  text-align: center;
  font-size: 10px;
  color: #94a3b8;
  transition: transform 0.2s;
  user-select: none;

  &.expanded {
    transform: rotate(90deg);
  }

  &:hover {
    color: #475569;
  }
}

.space {
  width: 16px;
}

.key {
  color: #1e293b;
  font-weight: 600;
}

.value {
  &.type-string {
    color: #059669;
  }
  &.type-number {
    color: #dc2626;
  }
  &.type-boolean {
    color: #7c3aed;
  }
  &.type-null {
    color: #64748b;
    font-style: italic;
  }
}

.preview {
  color: #94a3b8;
  font-style: italic;
}

/* 操作按钮区域 */
.actions {
  margin-left: auto;
  display: flex;
  gap: 4px;
  opacity: 0;
  transition: opacity 0.2s;
}

.btn-action {
  border: none;
  background: transparent;
  cursor: pointer;
  color: #64748b;
  font-size: 14px;
  width: 20px;
  height: 20px;
  border-radius: 4px;
  display: flex;
  align-items: center;
  justify-content: center;

  &:hover {
    background-color: #e2e8f0;
    color: #0f172a;
  }
}

/* 黑夜模式 */
.dark-mode {
  .line {
    &:hover {
      background-color: #374151;
    }
  }

  .arrow {
    color: #94a3b8;

    &:hover {
      color: #cbd5e1;
    }
  }

  .key {
    color: #e2e8f0;
  }

  .value {
    &.type-string {
      color: #34d399; /* 更亮的绿色 */
    }
    &.type-number {
      color: #f87171; /* 更亮的红色 */
    }
    &.type-boolean {
      color: #a78bfa; /* 更亮的紫色 */
    }
    &.type-null {
      color: #9ca3af; /* 更亮的灰色 */
    }
  }

  .preview {
    color: #9ca3af;
  }

  .btn-action {
    color: #9ca3af;

    &:hover {
      background-color: #4b5563;
      color: #f8fafc;
    }
  }
}

