.rule-editor-container {
  display: flex;
  flex-direction: column;
  height: 100%;
  background: #ffffff;
  color: #000000;
  position: relative; /* For modal positioning */
}

/* Header */
.editor-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 20px;
  border-bottom: 1px solid #e5e7eb;
  background: #fff;
  flex-shrink: 0;
}

.breadcrumb {
  display: flex;
  align-items: center;
  font-size: 15px;

  .text-btn {
    background: none;
    border: none;
    color: #4f46e5;
    cursor: pointer;
    padding: 0;
    font-weight: 600;
    &:hover {
      text-decoration: underline;
    }
  }

  .separator {
    margin: 0 10px;
    color: #9ca3af;
  }
  .current-rule {
    font-weight: 700;
    color: #111827;
    font-size: 16px;
  }
}

.error-state {
  padding: 40px;
  text-align: center;
  color: #ef4444;
}

/* Body Layout - Grid System */
.editor-body {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  background: #f3f4f6;
}

.task-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 16px;
  padding-bottom: 40px;
}

/* Task Cards */
.task-card {
  background: #ffffff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 16px;
  cursor: pointer;
  transition: all 0.2s ease;
  display: flex;
  flex-direction: column;
  box-shadow: 0 1px 2px rgba(0,0,0,0.05);
  position: relative;

  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    border-color: #d1d5db;

    .btn-icon-remove {
      opacity: 1;
    }
  }

  &.disabled {
    opacity: 0.7;
    background: #f9fafb;
    .task-name {
      text-decoration: line-through;
      color: #6b7280;
    }
  }
}

/* Remove Button on Card */
.btn-icon-remove {
  position: absolute;
  top: 12px;
  right: 12px;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  border: none;
  background: #fee2e2;
  color: #991b1b;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  opacity: 0; /* Hidden by default */
  transition: opacity 0.2s, background 0.2s;
  font-size: 16px;
  line-height: 1;
  z-index: 2;

  &:hover {
    background: #ef4444;
    color: white;
  }
}

/* Global Card Special Style */
.global-card {
  background: linear-gradient(to bottom right, #fff7ed, #ffffff);
  border-color: #fed7aa;
  grid-column: 1 / -1;

  .task-order {
    background: #ffedd5;
    color: #c2410c;
  }
  .card-desc {
    margin-top: 8px;
    font-size: 13px;
    color: #9a3412;
  }
  &:hover {
    border-color: #f97316;
  }
}

/* Add Card Style */
.add-card {
  border: 2px dashed #e5e7eb;
  background: transparent;
  align-items: center;
  justify-content: center;
  min-height: 120px;
  color: #6b7280;

  &:hover {
    border-color: #4f46e5;
    color: #4f46e5;
    background: #eef2ff;
  }

  .add-icon {
    font-size: 32px;
    line-height: 1;
    margin-bottom: 8px;
  }
  .add-text {
    font-weight: 600;
  }
}

/* Card Content */
.card-header {
  display: flex;
  align-items: center;
  margin-bottom: 12px;
  gap: 8px;
  padding-right: 20px; /* Space for remove button */
}

.task-order {
  font-size: 12px;
  background: #f3f4f6;
  color: #374151;
  padding: 2px 6px;
  border-radius: 4px;
  font-weight: 600;
}

.task-name {
  font-size: 16px;
  font-weight: 600;
  color: #111827;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  flex: 1;
}

.status-badge {
  font-size: 11px;
  padding: 2px 6px;
  border-radius: 10px;
  background: #e5e7eb;
  color: #4b5563;

  &.active {
    background: #dcfce7;
    color: #166534;
  }

  &.event-trigger {
    background: #e0e7ff;
    color: #3730a3;
  }
}

.card-body {
  font-size: 13px;
  color: #000000;
}

.info-row {
  display: flex;
  justify-content: space-between;
  margin-bottom: 4px;

  .label {
    color: #000000;
  }
  .value {
    font-weight: 500;
    &.comment {
      max-width: 180px;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
  }
}

.empty-tip {
  text-align: center;
  color: #9ca3af;
  margin-top: 40px;
  grid-column: 1 / -1;
}

/* Buttons */
.btn {
  padding: 8px 16px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-size: 14px;
  font-weight: 500;
  transition: background 0.2s;

  &.primary {
    background: #4f46e5;
    color: white;
    &:hover {
      background: #4338ca;
    }
  }

  &.secondary {
    background: #fff;
    border: 1px solid #d1d5db;
    color: #374151;
    &:hover {
      background: #f3f4f6;
    }
  }

  &.small {
    padding: 4px 10px;
    font-size: 12px;
  }
}

/* Custom Scrollbar */
.custom-scrollbar {
  &::-webkit-scrollbar {
    width: 8px;
  }
  &::-webkit-scrollbar-track {
    background: transparent;
  }
  &::-webkit-scrollbar-thumb {
    background: #d1d5db;
    border-radius: 4px;
  }
  &::-webkit-scrollbar-thumb:hover {
    background: #9ca3af;
  }
}

/* --- Modal Overlay Styles --- */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
}

.modal-content {
  background: white;
  border-radius: 8px;
  width: 500px;
  max-width: 90%;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  box-shadow: 0 10px 25px rgba(0,0,0,0.2);

  h3 {
    padding: 16px 20px;
    margin: 0;
    border-bottom: 1px solid #e5e7eb;
    font-size: 18px;
    color: #111827;
  }

  .modal-body {
    padding: 20px;
    overflow-y: auto;
    flex: 1;
  }

  .modal-footer {
    padding: 16px 20px;
    border-top: 1px solid #e5e7eb;
    display: flex;
    justify-content: flex-end;
    gap: 10px;
  }
}

.link-list {
  list-style: none;
  padding: 0;
  margin: 0;

  li {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px;
    border-bottom: 1px solid #f3f4f6;
    cursor: pointer;
    transition: background 0.2s;

    &:hover {
      background: #f9fafb;
    }

    .name {
      font-weight: 600;
      color: #374151;
    }
    .comment {
      font-size: 12px;
      color: #9ca3af;
      margin-left: 10px;
      flex: 1;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
  }
}

.no-data {
  text-align: center;
  color: #9ca3af;
  padding: 20px;
}

/* --- Dark Mode --- */
.rule-editor-container.dark-mode {
  background: #111827;
  color: #e2e8f0;

  .editor-header {
    background: #1f2937;
    border-bottom-color: #374151;
  }
  .breadcrumb .text-btn { color: #818cf8; }
  .breadcrumb .current-rule { color: #f3f4f6; }
  .breadcrumb .separator { color: #6b7280; }

  .editor-body {
    background: #111827;
  }

  .task-card {
    background: #1f2937;
    border-color: #374151;
    color: #e2e8f0;

    &:hover {
      background: #2d3748;
      border-color: #4b5563;
    }

    &.disabled {
      background: #1a202c;
      .task-name { color: #6b7280; }
    }
  }

  .global-card {
    background: linear-gradient(to bottom right, #431407, #1f2937);
    border-color: #7c2d12;
    .task-order { background: #7c2d12; color: #ffedd5; }
    .card-desc { color: #fdba74; }
    &:hover { border-color: #ea580c; }
  }

  .add-card {
    border-color: #374151;
    color: #6b7280;
    &:hover {
      border-color: #6366f1;
      color: #818cf8;
      background: rgba(99, 102, 241, 0.1);
    }
  }

  .task-name { color: #e2e8f0; }
  .task-order { background: #374151; color: #d1d5db; }
  .status-badge { background: #374151; color: #9ca3af; }
  .status-badge.active { background: #064e3b; color: #6ee7b7; }
  .status-badge.event-trigger { background: #312e81; color: #c7d2fe; }

  .card-body { color: #9ca3af; }
  .info-row .label { color: #6b7280 !important; }
  .info-row .value { color: #d1d5db; }

  /* Dark Mode for Modal */
  .modal-content {
    background: #1f2937;
    color: #e2e8f0;

    h3 {
      border-bottom-color: #374151;
      color: #e2e8f0;
    }

    .modal-footer {
      border-top-color: #374151;
    }
  }

  .link-list li {
    border-bottom-color: #374151;
    &:hover {
      background: #374151;
    }
    .name { color: #e2e8f0; }
  }

  .btn.secondary {
    background: #374151;
    border-color: #4b5563;
    color: #e2e8f0;
    &:hover {
      background: #4b5563;
    }
  }
}
