/* Modal Styles */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 1000;
}

.modal-container {
  width: 90%;
  max-width: 1000px;
  height: 85vh;
  background: #ffffff;
  border-radius: 8px;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  color: #000000;

  /* --- 深色模式覆盖 --- */
  &.dark-mode {
    background: #1f2937;
    color: #e2e8f0;

    .task-header { border-bottom-color: #374151; }
    .inner-tabs { border-bottom-color: #4b5563; }
    .tab-btn {
      color: #9ca3af;
      &:hover { color: #e2e8f0; }
      &.active { color: #818cf8; border-bottom-color: #818cf8; }
    }

    .form-group {
      label { color: #e2e8f0 !important; }
      .tip { color: #9ca3af; }

      input,
      textarea,
      select {
        background: #374151 !important;
        color: #e2e8f0 !important;
        border-color: #4b5563 !important;
        &:focus { border-color: #818cf8 !important; }
      }

      .comment-textarea {
        background: #374151 !important;
        color: #e2e8f0 !important;
        border-color: #4b5563 !important;
        &:focus { border-color: #818cf8 !important; }
      }
    }

    .name-input {
      color: #e2e8f0 !important;
      background: #374151 !important;
      &:hover, &:focus {
        background: #4b5563 !important;
        border-color: #4b5563 !important;
      }
    }

    .name-static {
      color: #e2e8f0 !important;
    }

    .list-sidebar { background: #111827; border-right-color: #4b5563; }
    .list-editor { border-color: #4b5563; }

    .sub-item {
      color: #9ca3af;
      border-bottom-color: #4b5563;
      &.active { background: #1f2937; color: #818cf8; }
      &:hover { background: #374151; }
    }

    .add-panel {
      background: #1f2937;
      border-bottom-color: #4b5563;
    }

    .list-content {
      background: #1f2937;
    }

    .sub-header { border-bottom-color: #4b5563; strong { color: #e2e8f0; } }
    .empty-sub { color: #9ca3af; }
    .close-btn { color: #e2e8f0; &:hover { background: #374151; } }

    .label { color: #e2e8f0 !important; }
    .text { color: #e2e8f0; }

    .toggle-switch {
      .slider { background: #4b5563; }
      input:checked + .slider { background: #6366f1; }
      .text { color: #e2e8f0; }
    }

    .event-badge {
      background: #312e81;
      color: #c7d2fe;
    }

    .checkbox-row label { color: #e2e8f0; }

    .btn.danger {
      background: #7f1d1d;
      color: #fecaca;
      &:hover { background: #991b1b; }
    }

    .btn.warning {
      background: #78350f;
      color: #fde68a;
      &:hover { background: #92400e; }
    }

    .btn.secondary {
      background: #374151;
      color: #e2e8f0;
      border: 1px solid #4b5563;
      &:hover:not(:disabled) {
        background: #4b5563;
        border-color: #6b7280;
      }
      &:disabled {
        background: #1f2937;
        color: #6b7280;
        border-color: #374151;
        opacity: 0.6;
      }
    }

    .custom-scrollbar {
      &::-webkit-scrollbar-thumb { background: #4b5563; }
      &::-webkit-scrollbar-thumb:hover { background: #6b7280; }
    }

    .lore-filter-container {
      background: #1f2937;
      border-color: #4b5563;

      .lore-filter-input {
        background: #374151 !important;
        color: #e2e8f0 !important;
        border-color: #4b5563 !important;
        &:focus { border-color: #818cf8 !important; }
      }

      .filter-info {
        color: #9ca3af;
        .info-item.highlight { color: #818cf8; }
        .info-item.selected { color: #34d399; }
      }
    }
  }
}

.task-editor {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: 20px;
}

.close-btn {
  font-size: 24px;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 4px;
  background: transparent;
  border: none;
  cursor: pointer;
  color: #111827;
  &:hover {
    background: #f3f4f6;
  }
}

/* Header */
.task-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
  padding-bottom: 10px;
  border-bottom: 1px solid #e5e7eb;
}

.task-title-edit {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;

  .label {
    font-size: 14px;
    color: #111827;
    font-weight: 600;
  }
  .name-input {
    font-size: 16px;
    font-weight: 600;
    border: 1px solid transparent;
    padding: 4px 8px;
    border-radius: 4px;
    color: #000000 !important;
    background: transparent;

    &:hover,
    &:focus {
      border-color: #9ca3af;
      background: #ffffff !important;
    }
  }
  .name-static {
    font-size: 16px;
    font-weight: 600;
    color: #000000;
  }
}

.task-actions {
  display: flex;
  align-items: center;
  gap: 12px;
}

/* Toggle Switch */
.toggle-switch {
  display: flex;
  align-items: center;
  cursor: pointer;
  gap: 6px;

  input { display: none; }
  .slider {
    width: 36px; height: 20px; background: #9ca3af; border-radius: 10px; position: relative; transition: 0.3s;
    &::after { content: ''; position: absolute; top: 2px; left: 2px; width: 16px; height: 16px; background: #fff; border-radius: 50%; transition: 0.3s; }
  }
  input:checked + .slider { background: #4f46e5; }
  input:checked + .slider::after { left: 18px; }
  .text { font-size: 12px; color: #111827; font-weight: 500; }
}

/* Event Badge */
.event-badge {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 4px 10px;
  background: #e0e7ff;
  color: #3730a3;
  border-radius: 12px;
  font-size: 12px;
  font-weight: 600;
  cursor: help;
  user-select: none;
}

/* Inner Tabs */
.inner-tabs {
  display: flex;
  gap: 4px;
  border-bottom: 1px solid #d1d5db;
  margin-bottom: 16px;
}

.tab-btn {
  padding: 8px 16px;
  background: transparent;
  border: none;
  border-bottom: 2px solid transparent;
  cursor: pointer;
  color: #374151;
  font-size: 13px;
  font-weight: 500;
  &:hover { color: #000000; }
  &.active { color: #4f46e5; border-bottom-color: #4f46e5; font-weight: 700; }
}

.tab-content {
  flex: 1;
  overflow-y: auto;
  padding-right: 6px;
}

.tab-pane {
  height: 100%;
  display: flex;
  flex-direction: column;
}

/* Forms */
.form-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 12px;
  margin-bottom: 16px;
  &.two-col { grid-template-columns: 1fr 1fr; }
  &.one-col { grid-template-columns: 1fr; }
}

.form-group {
  margin-bottom: 12px;
  label {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 12px;
    color: #000000 !important;
    margin-bottom: 4px;
    font-weight: 700;
  }

  input, textarea {
    width: 100%;
    padding: 6px 8px;
    border: 1px solid #d1d5db;
    border-radius: 4px;
    font-size: 13px;
    background: #ffffff !important;
    color: #000000 !important;

    &:focus { border-color: #4f46e5; outline: none; }
  }

  .comment-textarea {
    min-height: 80px;
    resize: vertical;
    font-family: inherit;
    line-height: 1.5;
  }

  &.full-height { flex: 1; display: flex; flex-direction: column; textarea { flex: 1; resize: none; } }
  &.full-width { grid-column: 1 / -1; }
  .tip { font-size: 11px; color: #4b5563; margin-bottom: 4px; font-weight: 500; }
  .inline-tip { margin-left: 8px; color: #dc2626; }
}

.checkbox-row {
  display: flex; align-items: center;
  label { display: flex; align-items: center; gap: 6px; cursor: pointer; margin: 0; color: #000000; font-weight: 600; }
  input { width: auto; }
}

/* List Editor */
.list-editor {
  display: flex; height: 100%; border: 1px solid #d1d5db; border-radius: 6px;
}

.list-sidebar {
  width: 180px; border-right: 1px solid #d1d5db; display: flex; flex-direction: column; background: #f3f4f6;
  border-top-left-radius: 6px; border-bottom-left-radius: 6px;
  .scroll-list { flex: 1; overflow-y: auto; }
  .sub-item {
    padding: 8px; font-size: 12px; cursor: pointer; border-bottom: 1px solid #e5e7eb; color: #111827; font-weight: 500;
    &:hover { background: #e5e7eb; }
    &.active { background: #ffffff; color: #4f46e5; font-weight: 700; border-left: 3px solid #4f46e5; }
  }
}

.add-panel {
  padding: 8px; border-bottom: 1px solid #e5e7eb; background: #ffffff;
  .mb-2 { margin-bottom: 6px; }
  .add-actions { display: flex; gap: 4px; .btn { flex: 1; } }
}

.list-content {
  flex: 1; padding: 12px; overflow-y: auto; background: #ffffff;
  border-top-right-radius: 6px; border-bottom-right-radius: 6px;
}

.sub-header {
  display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px; padding-bottom: 8px; border-bottom: 1px solid #e5e7eb;
  strong { color: #000000; font-size: 14px; }
}

.empty-sub { display: flex; height: 100%; align-items: center; justify-content: center; color: #4b5563; font-size: 13px; font-weight: 500; }

/* Regex UI Styles */
.regex-input-group {
  display: flex;
  gap: 8px;
  align-items: center;
  .flex-grow {
    flex: 1;
    font-weight: 600;
  }
  .preset-select-wrapper {
    width: 140px;
    flex-shrink: 0;
  }
}

input[placeholder*="正则"],
input[placeholder*="regex"] {
  font-weight: 600 !important;
}

.regex-list-container {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-bottom: 8px;
}
.regex-row {
  display: flex;
  gap: 8px;
  align-items: center;
  input { flex: 1; }
  .preset-select-wrapper {
    width: 100px;
    flex-shrink: 0;
    &.small { width: 100px; }
  }
}
.regex-actions {
  display: flex;
  gap: 8px;
}

/* Buttons */
.btn {
  padding: 6px 12px; border-radius: 4px; border: none; cursor: pointer; font-size: 13px; font-weight: 500;
  &.primary { background: #4f46e5; color: white; &:hover { background: #4338ca; } }
  &.danger { background: #fee2e2; color: #991b1b; &:hover { background: #fecaca; } }
  &.warning { background: #fef3c7; color: #92400e; &:hover { background: #fde68a; } }
  &.secondary {
    background: #f3f4f6;
    color: #374151;
    border: 1px solid #d1d5db;
    &:hover:not(:disabled) {
      background: #e5e7eb;
      border-color: #9ca3af;
    }
    &:disabled {
      background: #f9fafb;
      color: #9ca3af;
      border-color: #e5e7eb;
      opacity: 0.6;
    }
  }
  &.small { padding: 4px 8px; font-size: 12px; }
  &.icon-btn { font-size: 16px; line-height: 1; padding: 0 8px; }
  &.full { width: 100%; border-radius: 0; }
  &:disabled { opacity: 0.5; cursor: not-allowed; }
}

/* Custom Scrollbar */
.custom-scrollbar {
  &::-webkit-scrollbar { width: 6px; height: 6px; }
  &::-webkit-scrollbar-track { background: transparent; }
  &::-webkit-scrollbar-thumb { background: #d1d5db; border-radius: 3px; }
  &::-webkit-scrollbar-thumb:hover { background: #6b7280; }
}

/* New Styles for Lore Filter */
.lore-filter-container {
  background: #f9fafb;
  border: 1px solid #e5e7eb;
  border-radius: 6px;
  padding: 8px;

  .filter-row {
    display: flex;
    gap: 8px;
    margin-bottom: 6px;

    .lore-filter-input {
      flex: 1;
      padding: 4px 8px;
      border: 1px solid #d1d5db;
      border-radius: 4px;
      font-size: 13px;
      &:focus { border-color: #4f46e5; outline: none; }
    }

    .filter-actions {
      display: flex;
      gap: 4px;
      flex-shrink: 0;
    }
  }

  .filter-info {
    display: flex;
    gap: 12px;
    font-size: 11px;
    color: #6b7280;
    align-items: center;

    .info-item {
      &.highlight { color: #4f46e5; font-weight: 600; }
      &.selected { color: #059669; font-weight: 600; margin-left: auto; }
    }
  }
}
