.searchable-select {
  position: relative;
  width: 100%;
  font-size: 13px;

  &.is-disabled {
    opacity: 0.6;
    pointer-events: none;
  }
}

.select-trigger {
  min-height: 32px;
  padding: 4px 24px 4px 8px;
  border: 1px solid #e5e7eb;
  border-radius: 4px;
  background-color: #ffffff !important; /* 强制背景色 */
  cursor: pointer;
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  position: relative;
  color: #111827 !important; /* 强制字体颜色 */
  transition: border-color 0.2s;

  &:hover {
    border-color: #c7d2fe;
  }
}

.arrow-icon {
  position: absolute;
  right: 8px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 10px;
  color: #9ca3af;
  pointer-events: none;
}

.placeholder {
  color: #9ca3af;
}

.selected-text {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

/* Tags for multiple select */
.tags-container {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
}

.tag {
  background: #e0e7ff;
  color: #312e81;
  font-size: 12px;
  padding: 1px 6px;
  border-radius: 4px;
  display: flex;
  align-items: center;
  gap: 4px;
  border: 1px solid #c7d2fe;

  .remove-tag {
    cursor: pointer;
    font-weight: bold;
    line-height: 1;
    &:hover { color: #1e1b4b; }
  }
}

/* Dropdown Panel */
.dropdown-panel {
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  background-color: #ffffff !important; /* 强制背景色 */
  border: 1px solid #e5e7eb;
  border-radius: 4px;
  margin-top: 4px;
  max-height: 240px;
  overflow-y: auto;
  z-index: 10001;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);
}

.search-box {
  padding: 6px;
  border-bottom: 1px solid #f3f4f6;
  position: sticky;
  top: 0;
  background-color: #ffffff !important; /* 强制背景色 */
  z-index: 1;

  input {
    width: 100%;
    padding: 4px 8px;
    border: 1px solid #e5e7eb;
    border-radius: 4px;
    font-size: 12px;
    outline: none;

    /* 核心修复：强制浅色模式渲染，防止系统深色模式影响 */
    color-scheme: light;
    color: #111827 !important; /* 强制深色字体 */
    background-color: #ffffff !important; /* 强制白色背景 */

    &::placeholder {
      color: #9ca3af;
    }

    &:focus {
      border-color: #4f46e5;
    }
  }
}

.dropdown-item {
  padding: 6px 10px;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 8px;
  color: #111827;

  &:hover {
    background-color: #f3f4f6;
  }

  &.selected {
    background-color: #e0e7ff;
    color: #312e81;
    font-weight: 500;
  }

  input[type="checkbox"] {
    margin: 0;
    accent-color: #4f46e5; /* 优化复选框颜色 */
  }
}

.dropdown-tip {
  padding: 12px;
  text-align: center;
  color: #9ca3af;
  font-size: 12px;
}

/* Dark Mode Adaptation */
.dark-mode .searchable-select {
  .select-trigger {
    background-color: #111827 !important; /* 覆盖默认的 !important */
    border-color: #4b5563;
    color: #e2e8f0 !important; /* 覆盖默认的 !important */
  }

  .tag {
    background-color: #312e81;
    color: #e0e7ff;
    border-color: #818cf8;
  }

  .dropdown-panel {
    background-color: #1f2937 !important; /* 覆盖默认的 !important */
    border-color: #4b5563;
  }

  .search-box {
    background-color: #1f2937 !important; /* 覆盖默认的 !important */
    border-bottom-color: #374151;

    input {
      background-color: #111827 !important; /* 覆盖默认的 !important */
      border-color: #4b5563;
      color: #e2e8f0 !important; /* 覆盖默认的 !important */
      color-scheme: dark; /* 深色模式下强制深色渲染 */

      &::placeholder {
        color: #6b7280;
      }
    }
  }

  .dropdown-item {
    color: #e2e8f0;
    &:hover { background-color: #374151; }
    &.selected {
      background-color: #312e81;
      color: #e0e7ff;
    }
  }

  .placeholder {
    color: #6b7280;
  }

  .arrow-icon {
    color: #6b7280;
  }
}
